1	"use client";
2	
3	import { useAuth } from "@/entities/auth";
4	import {
5	  type Address,
6	  type UserNotificationsSetting,
7	  UserSetting,
8	  useAddresses,
9	  useDeleteAddress,
10	  useProfile,
11	  useUpdateProfilePhoto,
12	  useUpdateUserSettings,
13	  useUserSettings,
14	} from "@/entities/profile";
15	import {
16	  useFileUpload,
17	  useSignedFileUrl,
18	} from "@/shared/api/query-hooks/use-file-upload";
19	import type { SupportedCurrency } from "@/shared/config/currency-config";
20	import {
21	  CURRENCY_META,
22	  SUPPORTED_CURRENCIES,
23	} from "@/shared/config/currency-config";
24	import {
25	  IMAGE_ACCEPT_TYPES,
26	  type MimeType,
27	  S3_FOLDERS,
28	} from "@/shared/constants/mime-types";
29	import { KycRedirectHandler } from "@/shared/lib/kyc-redirect";
30	import { cn } from "@/shared/lib/utils";
31	import { getFullName } from "@/shared/lib/utils/get-full-name";
32	import { useCurrencyStore } from "@/shared/model/currency-store";
33	import { GoogleIcon } from "@/shared/ui/icons/google-icon";
34	import { UserAvatar } from "@/shared/ui/user-avatar/user-avatar";
35	import { toast } from "@/shared/ui/notification";
36	import { Button } from "@/shared/ui/shadcn/button";
37	import { Switch } from "@/shared/ui/shadcn/switch";
38	import { KycStatusSection } from "@/widgets/kyc-status-section";
39	import {
40	  BellRing,
41	  ChevronDown,
42	  KeyRound,
43	  MapPinHouse,
44	  RefreshCw,
45	  ShieldAlert,
46	  Trash2,
47	} from "lucide-react";
48	import { useSession } from "next-auth/react";
49	import dynamic from "next/dynamic";
50	import { type ReactNode, Suspense, useCallback, useRef, useState } from "react";
51	
52	const EditProfileModal = dynamic(
53	  () =>
54	    import("@/widgets/edit-profile-modal").then((mod) => ({
55	      default: mod.EditProfileModal,
56	    })),
57	  { ssr: false }
58	);
59	
60	const AddressModal = dynamic(
61	  () =>
62	    import("@/widgets/address-modal").then((mod) => ({
63	      default: mod.AddressModal,
64	    })),
65	  { ssr: false }
66	);
67	
68	// ---------------------------------------------------------------------------
69	// Constants
70	// ---------------------------------------------------------------------------
71	
72	const addressTypeLabels: Record<string, string> = {
73	  home: "Home/Residence",
74	  work: "Work/Office",
75	  other: "Other",
76	};
77	
78	// ---------------------------------------------------------------------------
79	// Primitives
80	// ---------------------------------------------------------------------------
81	
82	function SettingsCard({
83	  children,
84	  className,
85	}: {
86	  children: ReactNode;
87	  className?: string;
88	}) {
89	  return (
90	    <div
91	      className={cn(
92	        "flex flex-col gap-2 rounded-2xl border border-[#D6D3D1] bg-[#F5F3EF] p-6",
93	        className
94	      )}
95	    >
96	      {children}
97	    </div>
98	  );
99	}
100	
101	function CardHeader({ title, action }: { title: string; action?: ReactNode }) {
102	  return (
103	    <div className="mb-6 flex items-center justify-between gap-2">
104	      <h2 className="font-light font-new-serif text-2xl leading-[120%] tracking-[0px]">
105	        {title}
106	      </h2>
107	      {action}
108	    </div>
109	  );
110	}
111	
112	function SmallButton({
113	  onClick,
114	  children,
115	}: {
116	  onClick?: () => void;
117	  children: ReactNode;
118	}) {
119	  return (
120	    <Button
121	      className="rounded-lg border border-[#A8A29E] bg-[#F5F3EF] px-3 py-1.5 font-medium font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
122	      onClick={onClick}
123	      type="button"
124	    >
125	      {children}
126	    </Button>
127	  );
128	}
129	
130	function FieldBox({ children }: { children: ReactNode }) {
131	  return (
132	    <div className="flex flex-col gap-3 rounded-xl border border-[#E7E5E4] bg-[#EDE9E3] px-5 py-[28px]">
133	      {children}
134	    </div>
135	  );
136	}
137	
138	function FieldLabel({ children }: { children: ReactNode }) {
139	  return (
140	    <span className="font-new-sans text-base leading-[150%] tracking-[-1%]">
141	      {children}
142	    </span>
143	  );
144	}
145	
146	function FieldValue({
147	  children,
148	  muted,
149	}: {
150	  children: ReactNode;
151	  muted?: boolean;
152	}) {
153	  return (
154	    <span
155	      className={cn(
156	        "font-new-serif text-2xl leading-[120%] tracking-[0px]",
157	        muted ? "text-[#A8A29E]" : "text-[#44403C]"
158	      )}
159	    >
160	      {children}
161	    </span>
162	  );
163	}
164	
165	// ---------------------------------------------------------------------------
166	// Profile Picture card
167	// ---------------------------------------------------------------------------
168	
169	function ProfilePictureCard({
170	  photoFileId,
171	  firstName,
172	}: {
173	  photoFileId: string | null;
174	  firstName: string;
175	}) {
176	  const fileInputRef = useRef<HTMLInputElement>(null);
177	  const { mutate: updatePhoto, isPending: isUpdating } =
178	    useUpdateProfilePhoto();
179	  const { mutate: uploadFile, isPending: isUploading } = useFileUpload();
180	  const { data: photoData } = useSignedFileUrl(
181	    photoFileId ?? "",
182	    !!photoFileId
183	  );
184	
185	  const isPending = isUploading || isUpdating;
186	
187	  function handleReplaceClick() {
188	    fileInputRef.current?.click();
189	  }
190	
191	  function handleFileChange(event: React.ChangeEvent<HTMLInputElement>) {
192	    const file = event.target.files?.[0];
193	    if (!file) return;
194	
195	    uploadFile(
196	      {
197	        file,
198	        folder: S3_FOLDERS.STATIC,
199	        mime: file.type as MimeType,
200	        fileName: file.name,
201	      },
202	      {
203	        onSuccess: (uploaded) => {
204	          updatePhoto(
205	            { photoFileId: uploaded.fileId },
206	            {
207	              onSuccess: () => toast.success("Profile picture updated"),
208	              onError: () => toast.error("Failed to update profile picture"),
209	            }
210	          );
211	        },
212	      }
213	    );
214	
215	    // Reset input so the same file can be re-selected
216	    event.target.value = "";
217	  }
218	
219	  function handleDelete() {
220	    updatePhoto(
221	      { photoFileId: null },
222	      {
223	        onSuccess: () => toast.success("Profile picture removed"),
224	        onError: () => toast.error("Failed to remove profile picture"),
225	      }
226	    );
227	  }
228	
229	  return (
230	    <SettingsCard>
231	      <CardHeader title="Profile Picture" />
232	
233	      <div className="new-design flex items-center justify-between gap-3 rounded-lg bg-[#EDE9E3] p-4 text-center">
234	        {/* Avatar */}
235	        <div className="h-9 w-9 shrink-0 overflow-hidden rounded-[4px]">
236	          <UserAvatar firstName={firstName} size={36} src={photoData?.url} />
237	        </div>
238	
239	        {/* Actions */}
240	        <div className="flex items-center gap-4">
241	          <button
242	            className="rounded-lg border border-[#A8A29E] bg-[#F5F3EF] px-3 py-1.5 font-medium font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
243	            disabled={isPending}
244	            onClick={handleReplaceClick}
245	            type="button"
246	          >
247	            {isUploading ? "Uploading…" : "Replace Profile Image"}
248	          </button>
249	
250	          {photoFileId && (
251	            <button
252	              aria-label="Remove profile picture"
253	              className="transition-colors hover:text-[#44403C]"
254	              disabled={isPending}
255	              onClick={handleDelete}
256	              type="button"
257	            >
258	              <Trash2 className="h-5 w-5" />
259	            </button>
260	          )}
261	        </div>
262	      </div>
263	
264	      <input
265	        accept={IMAGE_ACCEPT_TYPES}
266	        className="hidden"
267	        onChange={handleFileChange}
268	        ref={fileInputRef}
269	        type="file"
270	      />
271	    </SettingsCard>
272	  );
273	}
274	
275	// ---------------------------------------------------------------------------
276	// Notifications card (real API)
277	// ---------------------------------------------------------------------------
278	
279	function NotificationsCard() {
280	  const { data: userSettings, isLoading } = useUserSettings();
281	  const updateMutation = useUpdateUserSettings();
282	  const debounceRef = useRef<NodeJS.Timeout | null>(null);
283	
284	  const notif = userSettings?.[UserSetting.Notifications] ?? null;
285	
286	  const handleToggle = useCallback(
287	    (field: keyof UserNotificationsSetting, value: boolean) => {
288	      if (!notif) return;
289	      if (debounceRef.current) clearTimeout(debounceRef.current);
290	      debounceRef.current = setTimeout(() => {
291	        updateMutation.mutate(
292	          { [UserSetting.Notifications]: { ...notif, [field]: value } },
293	          {
294	            onSuccess: () => toast.success("Settings updated"),
295	            onError: () => toast.error("Failed to update settings"),
296	          }
297	        );
298	      }, 300);
299	    },
300	    [notif, updateMutation]
301	  );
302	
303	  const items: {
304	    field: keyof UserNotificationsSetting;
305	    icon: ReactNode;
306	    title: string;
307	    description: string;
308	  }[] = [
309	    {
310	      field: "general",
311	      icon: <BellRing className="h-5 w-5 shrink-0 text-[#78716C]" />,
312	      title: "General Notification",
313	      description: "Enable all Notification for Updates and Alerts",
314	    },
315	    {
316	      field: "buyback",
317	      icon: <RefreshCw className="h-5 w-5 shrink-0 text-[#78716C]" />,
318	      title: "BuyBack Notifications",
319	      description: "Alerts for BuyBack Repayment, due dates etc",
320	    },
321	    {
322	      field: "accountSecurity",
323	      icon: <ShieldAlert className="h-5 w-5 shrink-0 text-[#78716C]" />,
324	      title: "Account Security Alerts",
325	      description: "Notifications for login attempts, password changes",
326	    },
327	  ];
328	
329	  return (
330	    <SettingsCard>
331	      <CardHeader title="Notification settings" />
332	
333	      <div className="flex flex-col divide-y divide-[#E7E5E4]">
334	        {isLoading
335	          ? [1, 2, 3].map((i) => (
336	              <div
337	                className="h-14 animate-pulse bg-[#F5F3EF] first:rounded-t-xl last:rounded-b-xl"
338	                key={i}
339	              />
340	            ))
341	          : items.map(({ field, icon, title, description }) => (
342	              <div
343	                className="flex items-center gap-4 py-3 first:pt-0 last:pb-0"
344	                key={field}
345	              >
346	                {icon}
347	                <div className="flex flex-1 flex-col leading-[150%] tracking-[-1%]">
348	                  <span className="font-medium font-new-sans text-sm">
349	                    {title}
350	                  </span>
351	                  <span className="font-new-sans text-sm">{description}</span>
352	                </div>
353	                <Switch
354	                  checked={notif?.[field] ?? false}
355	                  disabled={!notif}
356	                  onCheckedChange={(value) => handleToggle(field, value)}
357	                />
358	              </div>
359	            ))}
360	      </div>
361	    </SettingsCard>
362	  );
363	}
364	
365	// ---------------------------------------------------------------------------
366	// Main page
367	// ---------------------------------------------------------------------------
368	
369	export function ProfilePage() {
370	  const { isAuthenticator } = useAuth();
371	  const { data: session } = useSession();
372	  const { data: profile } = useProfile();
373	  const { data: addressesData } = useAddresses();
374	  const addresses = Array.isArray(addressesData) ? addressesData : [];
375	  const { mutate: deleteAddress } = useDeleteAddress();
376	  const { mutate: updateSettings } = useUpdateUserSettings();
377	  const currency = useCurrencyStore((state) => state.currency);
378	
379	  const [isEditProfileOpen, setIsEditProfileOpen] = useState(false);
380	  const [isAddressModalOpen, setIsAddressModalOpen] = useState(false);
381	  const [selectedAddress, setSelectedAddress] = useState<Address | null>(null);
382	
383	  function handleCurrencyChange(newCurrency: SupportedCurrency) {
384	    updateSettings(
385	      { [UserSetting.Currency]: newCurrency },
386	      {
387	        onSuccess: () => {
388	          useCurrencyStore.getState().setCurrency(newCurrency);
389	          toast.success("Currency updated");
390	        },
391	        onError: () => toast.error("Failed to update currency"),
392	      }
393	    );
394	  }
395	
396	  function openAddressModal(addr: Address | null) {
397	    setSelectedAddress(addr);
398	    setIsAddressModalOpen(true);
399	  }
400	
401	  // Determine auth provider from idToken prefix / session provider field
402	  const isGoogleAuth = (() => {
403	    const idToken = session?.idToken ?? "";
404	    return idToken.toLowerCase().includes("google");
405	  })();
406	
407	  if (!profile) return null;
408	
409	  return (
410	    <>
411	      {!isAuthenticator && (
412	        <Suspense fallback={null}>
413	          <KycRedirectHandler />
414	        </Suspense>
415	      )}
416	
417	      {/* Page header */}
418	      <div className="new-design mx-auto mb-8 flex w-full max-w-[600px] flex-col items-center gap-2 px-4 pt-10 text-center">
419	        <h1 className="font-extralight font-new-serif text-3xl leading-[120%] tracking-[0]">
420	          Profile Settings
421	        </h1>
422	        <p className="font-new-sans text-base leading-[150%] tracking-[-1%]">
423	          Update your information, see your verification status, and adjust
424	          <br className="hidden sm:block" />
425	          your notification preferences, all in one place.
426	        </p>
427	      </div>
428	
429	      <div className="mx-auto flex w-full max-w-[600px] flex-col gap-4 px-4 pb-16">
430	        {/* ---------------------------------------------------------------- */}
431	        {/* Card 1: Profile Details                                           */}
432	        {/* ---------------------------------------------------------------- */}
433	        <SettingsCard>
434	          <CardHeader
435	            action={
436	              <SmallButton onClick={() => setIsEditProfileOpen(true)}>
437	                Edit
438	              </SmallButton>
439	            }
440	            title="Profile Details"
441	          />
442	
443	          {/* Auth provider row + Name + UID */}
444	          <div className="flex flex-col gap-3 rounded-xl border border-[#E7E5E4] bg-[#EDE9E3] px-5 py-[28px]">
445	            <div className="flex items-center gap-1.5">
446	              {isGoogleAuth ? (
447	                <GoogleIcon className="h-3.5 w-3.5" />
448	              ) : (
449	                <KeyRound className="h-3.5 w-3.5 text-[#A8A29E]" />
450	              )}
451	              <span className="font-new-sans text-base leading-[150%] tracking-[-1%]">
452	                {isGoogleAuth ? "Google" : "Full name"}
453	              </span>
454	            </div>
455	            <div className="flex items-center justify-between gap-2">
456	              <span className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">
457	                {getFullName(profile)}
458	              </span>
459	              <span className="rounded-sm bg-[#ECFDF5] px-2 py-0.5 font-new-sans text-[#047857] text-xs">
460	                UID-{profile.id.slice(0, 4)}
461	              </span>
462	            </div>
463	          </div>
464	
465	          {/* Email */}
466	          <FieldBox>
467	            <FieldLabel>Email</FieldLabel>
468	            <FieldValue>{profile.email}</FieldValue>
469	          </FieldBox>
470	
471	          {/* Phone */}
472	          <FieldBox>
473	            <FieldLabel>Phone number</FieldLabel>
474	            <FieldValue muted={!profile.phone}>
475	              {profile.phone || "Add your phone number"}
476	            </FieldValue>
477	          </FieldBox>
478	        </SettingsCard>
479	
480	        {/* ---------------------------------------------------------------- */}
481	        {/* Card 2: Profile Picture                                           */}
482	        {/* ---------------------------------------------------------------- */}
483	        <ProfilePictureCard firstName={profile.firstName} photoFileId={profile.photoFileId} />
484	
485	        {/* ---------------------------------------------------------------- */}
486	        {/* Card 3: Account Verification (KYC)                               */}
487	        {/* ---------------------------------------------------------------- */}
488	        {!isAuthenticator && <KycStatusSection />}
489	
490	        {/* ---------------------------------------------------------------- */}
491	        {/* Card 3: Registered Addresses                                     */}
492	        {/* ---------------------------------------------------------------- */}
493	        <SettingsCard>
494	          <CardHeader
495	            action={
496	              <SmallButton onClick={() => openAddressModal(null)}>
497	                Add Address
498	              </SmallButton>
499	            }
500	            title="Registered Addresses"
501	          />
502	
503	          {addresses.length === 0 && (
504	            <div className="flex items-start gap-3 rounded-xl border border-[#E7E5E4] bg-[#EDE9E3] px-4 py-3">
505	              <MapPinHouse className="mt-0.5 h-4 w-4 shrink-0 text-[#A8A29E]" />
506	              <div className="flex flex-col gap-0.5">
507	                <span className="font-bold font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-1%]">
508	                  Add your first address
509	                </span>
510	                <span className="font-new-sans text-xs leading-[150%] tracking-[-1%]">
511	                  Reminder: Your address is missing from your profile. Please
512	                  update it at the earliest to ensure uninterrupted service and
513	                  smooth processing.
514	                </span>
515	              </div>
516	            </div>
517	          )}
518	
519	          {addresses?.map((addr) => (
520	            <button
521	              className="new-design relative flex w-full flex-row items-start gap-3 rounded-2xl bg-[#EDE9E3] px-5 py-4 text-left transition-all hover:bg-[#EDE9E3]/80"
522	              key={addr.id}
523	              onClick={() => openAddressModal(addr)}
524	              type="button"
525	            >
526	              <MapPinHouse className="mt-0.5 h-5 w-5 shrink-0" />
527	
528	              <div className="flex flex-1 flex-col gap-1">
529	                <span className="font-bold text-sm leading-tight">
530	                  {(addr.addressType &&
531	                    addressTypeLabels[addr.addressType.toLowerCase()]) ||
532	                    addr.addressType ||
533	                    "Address"}
534	                </span>
535	                <p className="max-w-[90%] text-sm leading-relaxed">
536	                  {addr.addressLine1}
537	                  {addr.addressLine2 ? `, ${addr.addressLine2}` : ""}
538	                  {`, ${addr.city}, ${addr.country?.name}`}
539	                  {addr.zip ? `, ${addr.zip}` : ""}
540	                </p>
541	                {addr.isPrimary && (
542	                  <div className="mt-2 w-fit rounded-lg bg-[#ECFDF5] px-3 py-1">
543	                    <span className="font-medium text-[#047857] text-sm">
544	                      Primary Address
545	                    </span>
546	                  </div>
547	                )}
548	              </div>
549	              <Button
550	                aria-label="Delete address"
551	                className="absolute top-1 right-2 p-2 transition-colors hover:text-[#44403C]"
552	                onClick={(event) => {
553	                  event.stopPropagation();
554	                  deleteAddress(addr.id, {
555	                    onSuccess: () =>
556	                      toast.success("Address deleted successfully"),
557	                    onError: () => toast.error("Failed to delete address"),
558	                  });
559	                }}
560	                role="button"
561	                variant={"simple"}
562	              >
563	                <Trash2 className="h-5 w-5" />
564	              </Button>
565	            </button>
566	          ))}
567	        </SettingsCard>
568	
569	        {/* ---------------------------------------------------------------- */}
570	        {/* Card 4: Set Currency                                              */}
571	        {/* ---------------------------------------------------------------- */}
572	        <SettingsCard className="gap-0">
573	          <div className="flex items-center justify-between">
574	            <h2 className="font-light font-new-serif text-2xl leading-[120%]">
575	              Set Currency
576	            </h2>
577	            <div className="relative">
578	              <Button
579	                className="flex items-center gap-1.5 rounded-lg border border-[#A8A29E] bg-[#F5F3EF] px-3 py-1.5 font-medium font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
580	                onClick={(event) => {
581	                  const select = event.currentTarget
582	                    .nextElementSibling as HTMLSelectElement | null;
583	                  select?.focus();
584	                  select?.click();
585	                }}
586	                type="button"
587	              >
588	                {CURRENCY_META[currency].flag} {currency}
589	                <ChevronDown className="h-3.5 w-3.5" />
590	              </Button>
591	              <select
592	                aria-label="Select currency"
593	                className="absolute inset-0 cursor-pointer opacity-0"
594	                onChange={(event) =>
595	                  handleCurrencyChange(event.target.value as SupportedCurrency)
596	                }
597	                value={currency}
598	              >
599	                {SUPPORTED_CURRENCIES.map((cur) => (
600	                  <option key={cur} value={cur}>
601	                    {CURRENCY_META[cur].flag} {cur}
602	                  </option>
603	                ))}
604	              </select>
605	            </div>
606	          </div>
607	        </SettingsCard>
608	
609	        {/* ---------------------------------------------------------------- */}
610	        {/* Card 5: Notification settings (real API, moved from Settings)    */}
611	        {/* ---------------------------------------------------------------- */}
612	        <NotificationsCard />
613	      </div>
614	
615	      <EditProfileModal
616	        onOpenChange={setIsEditProfileOpen}
617	        open={isEditProfileOpen}
618	        profile={profile}
619	      />
620	
621	      <AddressModal
622	        address={selectedAddress}
623	        onOpenChange={setIsAddressModalOpen}
624	        open={isAddressModalOpen}
625	      />
626	    </>
627	  );
628	}
