import type { DefaultSession } from "next-auth";
import type { DefaultJWT } from "next-auth/jwt";
import type { Profile } from "@/entities/profile";

declare module "next-auth" {
  interface Session {
    accessToken: string;
    refreshToken: string;
    idToken: string;
    refreshTokenExpiresAt?: number;
    session?: string;
    isTemporaryPassword?: boolean;
    tempPasswordSession?: string;
    user: {
      id: string;
      email: string;
      profile?: Profile;
    } & DefaultSession["user"];
  }

  interface User {
    id: string;
    email: string;
    accessToken: string;
    refreshToken: string;
    idToken: string;
    refreshTokenExpiresAt?: number;
    session?: string;
    profile?: Profile;
    isTemporaryPassword?: boolean;
    tempPasswordSession?: string;
  }
}

declare module "next-auth/jwt" {
  interface JWT extends DefaultJWT {
    id: string;
    email: string;
    accessToken: string;
    refreshToken: string;
    idToken: string;
    refreshTokenExpiresAt?: number;
    session?: string;
    profile?: Profile;
    isTemporaryPassword?: boolean;
    tempPasswordSession?: string;
  }
}

