import { cn } from "@/shared/lib/ui/cn";
import type { ComponentProps, FC } from "react";
import { memo } from "react";

type UaePassIconProps = ComponentProps<"div">;

const UaePassIconComponent: FC<UaePassIconProps> = ({ className, ...rest }) => (
  <div
    aria-label="UAE Pass logo"
    className={cn("h-[15px] w-[15px] rounded-[10px] bg-[#D9D9D9]", className)}
    {...rest}
  />
);

